// Extract and validate input parameters
const body = $input.first().json.body || $input.first().json;

const topic = body.topic || 'AI productivity tools';
const style = body.style || 'educational';
const duration = body.duration || 'medium';

// Map duration to approximate seconds
const durationMap = {
  'short': 60,
  'medium': 240,
  'long': 600
};

return {
  json: {
    topic: topic,
    style: style,
    duration: duration,
    targetSeconds: durationMap[duration] || 240
  }
};

// Combine RAG results into context string
const ragResponse = $input.first().json;
const inputData = $('Validate Input').first().json;

let contextChunks = [];

if (ragResponse.chunks && ragResponse.chunks.length > 0) {
  ragResponse.chunks.forEach(chunk => {
    contextChunks.push(`[${chunk.doc_type}] ${chunk.content}`);
  });
}

const ragContext = contextChunks.length > 0 
  ? contextChunks.join('\n\n')
  : 'No specific brand context found. Use general best practices for engaging YouTube content.';

return {
  json: {
    topic: inputData.topic,
    style: inputData.style,
    duration: inputData.duration,
    targetSeconds: inputData.targetSeconds,
    ragContext: ragContext,
    contextChunksCount: contextChunks.length
  }
};

