// Parse Claude's response and extract the script JSON
const claudeResponse = $input.first().json;
const inputData = $('Build Prompt Context').first().json;

let script = {};

try {
  const content = claudeResponse.content?.[0]?.text || '';

  // Find JSON in the response
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    script = JSON.parse(jsonMatch[0]);
  } else {
    throw new Error('No JSON found in response');
  }

  // Calculate total duration
  let totalDuration = 0;
  if (script.sections) {
    script.sections.forEach(section => {
      totalDuration += section.duration_seconds || 0;
    });
  }
  script.total_duration_seconds = totalDuration;

} catch (e) {
  script = {
    error: true,
    message: 'Failed to parse script: ' + String(e),
    raw_response: claudeResponse.content?.[0]?.text?.substring(0, 500)
  };
}

return {
  json: {
    success: !script.error,
    topic: inputData.topic,
    style: inputData.style,
    generatedAt: new Date().toISOString(),
    script: script,
    ragContextUsed: inputData.contextChunksCount > 0
  }
};
